            this.c_sum_loan_coll.DataMember = "Query";
            this.c_sum_loan_coll.Expression = "[LOAN_BURDEN] + [COLL_AMOUNT] + [COLL_AMOUNT_CHAR]";
            this.c_sum_loan_coll.Name = "c_sum_loan_coll";
            // 
            // c_salary_loan
            // 
            this.c_salary_loan.DataMember = "Query";
            this.c_salary_loan.Expression = "[LOAN_BURDEN] / [SALARY_AMOUNT]";
            this.c_salary_loan.Name = "c_salary_loan";
            // 
            // c_cap_loan
            // 
            this.c_cap_loan.DataMember = "Query";
            this.c_cap_loan.Expression = "[LOAN_BURDEN] / ([TOTAL_SHARE_VALUE] + [INSURE_AMOUNT] + [RETIRE_PROVIDENT_FUND]+" +
    "[DEP_AMOUNT])";
            this.c_cap_loan.Name = "c_cap_loan";
            // 
            // c_obj
            // 
            this.c_obj.DataMember = "Query";
            this.c_obj.Expression = "Iif([LOAN_OBJECTIVE_CODE] is null,0,1)";
            this.c_obj.Name = "c_obj";
            // 
            // c_rate_loan
            // 
            this.c_rate_loan.DataMember = "Query";
            this.c_rate_loan.Expression = "Iif([c_cap_loan] > 1.50,\'อัตราส่วนหนี้สินต่อทุนมากกว่า 1.50 เท่า\',\'\')";
            this.c_rate_loan.Name = "c_rate_loan";
            // 
            // c_salary_no_per
            // 
            this.c_salary_no_per.DataMember = "Query";
            this.c_salary_no_per.Expression = "Iif([BALANCE_SAL_NO_HANG] = 0,1,[BALANCE_SAL_NO_HANG])/iif([SALARY_AMOUNT] = 0,1," +
    "[SALARY_AMOUNT])*100";
            this.c_salary_no_per.Name = "c_salary_no_per";
            // 
            // c_salary_per
            // 
            this.c_salary_per.DataMember = "Query";
            this.c_salary_per.Expression = "Iif([BALANCE_SALARY] = 0,1,[BALANCE_SALARY])/iif([SALARY_AMOUNT] = 0,1,[SALARY_AM" +
    "OUNT])*100";
            this.c_salary_per.Name = "c_salary_per";
            // 
            // c_shar_per
            // 
            this.c_shar_per.DataMember = "Query";
            this.c_shar_per.Expression = "Iif([TOTAL_SHARE_VALUE] = 0,0,([TOTAL_SHARE_VALUE]/[MEM_REQUEST_AMOUNT])*100)";
            this.c_shar_per.Name = "c_shar_per";
            // 
            // c_dep66_per
            // 
            this.c_dep66_per.DataMember = "Query";
            this.c_dep66_per.Expression = "Iif([INSURE_AMOUNT] = 0,0,([INSURE_AMOUNT]/[MEM_REQUEST_AMOUNT])*100)";
            this.c_dep66_per.Name = "c_dep66_per";
            // 
            // c_provident_fund_per
            // 
            this.c_provident_fund_per.DataMember = "Query";
            this.c_provident_fund_per.Expression = "Iif([PROVIDENT_FUND] = 0,0,([PROVIDENT_FUND]/[MEM_REQUEST_AMOUNT])*100)";
            this.c_provident_fund_per.Name = "c_provident_fund_per";
            // 
            // c_retire_provident_per
            // 
            this.c_retire_provident_per.DataMember = "Query";
            this.c_retire_provident_per.Expression = "Iif([RETIRE_PROVIDENT_FUND] = 0,0,([RETIRE_PROVIDENT_FUND]/[MEM_REQUEST_AMOUNT])*" +
    "100)";
            this.c_retire_provident_per.Name = "c_retire_provident_per";
            // 
            // c_sum_loan_hang
            // 
            this.c_sum_loan_hang.DataMember = "Query";
            this.c_sum_loan_hang.Expression = "[RETIRE_PAID]+[TOTAL_CREM_BALANCE]+[TOTAL_SPECIAL_BALANCE]";
            this.c_sum_loan_hang.Name = "c_sum_loan_hang";
            // 
            // c_remark
            // 
            this.c_remark.DataMember = "Query";
            this.c_remark.Expression = "Iif([LOAN_OBJECTIVE_DESCRIPTION] = \'อื่น ๆ\',[REMARK],\'\')";
            this.c_remark.Name = "c_remark";
